INSERT INTO `reviews` VALUES (1,5,'가계해수욕장은 고운 모래사장과 드넓은 갯벌이 공존해, 물때에 맞춰 부드러운 해수욕과 생동감 넘치는 조개 캐기 체험을 동시에 즐길 수 있어 정말 매력적이었습니다.\n\n해변 뒤편으로는 울창한 송림이 시원한 그늘을 드리워주어, 텐트를 치고 바닷바람을 맞으며 캠핑이나 피크닉을 즐기기에 더할 나위 없이 아늑하고 평화로운 분위기였습니다.\n\n특히 해 질 무렵, 붉게 타오르는 낙조가 잔잔한 수면 위로 황금빛 윤슬을 만들어내는 풍경은 넋을 잃고 바라볼 정도로 아름다운 장관이었습니다.\n\n사람이 너무 붐비지 않아 여유로웠고, 신비의 바닷길과 해양생태관 등 볼거리도 풍성해 가족이나 연인과 함께 오붓하게 힐링하기에 최고의 장소였습니다.',NULL,'[]',0,'2025-12-24 02:26:28.933640','2025-12-24 02:26:28.933640',1,2);
/*!40000 ALTER TABLE `reviews` ENABLE KEYS */;
UNLOCK TABLES;

